// Compliant: Each statement on its own line
func processUser(user User) error {
    validate(user)
    save(user)
    notify(user)

    if user.IsActive {
        activate(user)
        sendEmail(user)
    }

    // Loop with clear statement separation
    for _, item := range user.Items {
        process(item)
        log(item.ID)
        update(item)
    }

    // Variable declarations on separate lines
    var name string
    var email string
    var age int
    var active bool

    // Clear separation of operations
    result := calculate(user.Age)
    log.Printf("Result: %d", result)

    // Proper error handling
    if err := validateUser(user); err != nil {
        return err
    }

    // Multiple assignments separated
    x, y := 1, 2
    z := x + y
    fmt.Println(z)

    return nil
}

// Compliant: Clear switch case structure
func handleUserAction(action string) {
    switch action {
    case "create":
        createUser()
        logAction("create")
        incrementCounter()
    case "delete":
        deleteUser()
        logAction("delete")
        decrementCounter()
    case "update":
        updateUser()
        logAction("update")
        notifyChange()
    }
}

// Compliant: Proper initialization sequence
func initialize() {
    config := loadConfig()
    db := connectDB()
    cache := setupCache()
    startServer(config, db, cache)
}

// Compliant: When single-line statements are appropriate
func simpleOperations() {
    // Short, simple statements can sometimes be on one line if very clear
    x := 1
    y := 2
    z := x + y

    // But prefer separation for debugging and clarity
    if z > 2 {
        fmt.Println("Sum is greater than 2")
    }
}

// Compliant: Error handling with proper separation
func robustProcessing(data []byte) error {
    content, err := parse(data)
    if err != nil {
        return fmt.Errorf("parsing failed: %w", err)
    }

    result, err := process(content)
    if err != nil {
        return fmt.Errorf("processing failed: %w", err)
    }

    err = save(result)
    if err != nil {
        return fmt.Errorf("saving failed: %w", err)
    }

    return nil
}
